import random

token_probabilities = {
    "start": {
        "【重要】": 0.15, "【限定】": 0.12, "【今週末まで】": 0.10,
        "【お知らせ】": 0.09, "季節の": 0.08, "期間限定": 0.08,
        "あなたへの": 0.07, "特別な": 0.06, "新商品": 0.05, "ありがとう": 0.04,
    },
    "middle": {
        "特別オファー": 0.18, "セール開催中": 0.15, "キャンペーン": 0.13,
        "ご案内": 0.12, "限定プレゼント": 0.10, "お得情報": 0.09, "割引クーポン": 0.08,
    },
    "end": {
        "をお見逃しなく": 0.20, "〜詳細はこちら": 0.18, "が届いています": 0.15,
        "のご連絡": 0.12, "は本日限り！": 0.10,
    }
}

def sample_token(prob_dict, temperature=1.0):
    tokens = list(prob_dict.keys())
    probs = list(prob_dict.values())
    adjusted = [p ** (1 / temperature) for p in probs]
    total = sum(adjusted)
    adjusted = [p / total for p in adjusted]
    return random.choices(tokens, weights=adjusted, k=1)[0]

for temp in [0.3, 1.0, 1.8]:
    print(f"\n=== Temperature={temp} ===")
    for i in range(3):
        t1 = sample_token(token_probabilities["start"], temp)
        t2 = sample_token(token_probabilities["middle"], temp)
        t3 = sample_token(token_probabilities["end"], temp)
        print(f"  {i+1}: {t1}{t2}{t3}")
